rentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>' . esc_html($nivel) . '</p>'; if ($plazas) echo '<p class="flex items-center gap-2"><svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z"/></svg>' . esc_html($plazas) . ' plazas</p>'; echo '</div>'; if ($precio) echo '<p class="text-2xl font-bold text-primary mb-4">' . esc_html($precio) . '€</p>'; echo '<a href="' . get_permalink() . '" class="block text-center px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark">Ver Curso</a></div></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><h3 class="text-2xl font-bold">No hay cursos disponibles</h3></div>'; endif; wp_reset_postdata(); ?></main></div></div><?php get_footer(); ?>
